  padding: 40px 20px 80px;
}

/* ── Header ───────────────────────────────────────────────────────────── */
header {
  text-align: center;
  margin-bottom: 36px;
}
.logo {
  font-size: 2rem;
  font-weight: 800;
  color: var(--primary);
  letter-spacing: -0.5px;
}
.tagline {
  margin-top: 6px;
  color: var(--muted);
  font-size: 0.95rem;
}

/* ── Card ─────────────────────────────────────────────────────────────── */
.card {
  background: var(--card);
  border-radius: var(--radius);
  padding: 28px 32px;
  box-shadow: 0 2px 16px rgba(0,0,0,0.07);
  margin-bottom: 20px;
}
.card h2 {
  font-size: 1.1rem;
  font-weight: 700;
  margin-bottom: 20px;
  color: var(--text);
}

/* ── Form ─────────────────────────────────────────────────────────────── */
.field {
  display: flex;
  flex-direction: column;
  gap: 6px;
  flex: 1;
}
.field label {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text);
}
.required { color: var(--danger); }
.optional { color: var(--muted); font-weight: 400; }

input[type="text"],
input[type="url"],
select {
  padding: 10px 14px;
  border: 1.5px solid var(--border);
  border-radius: 8px;
  font-size: 0.95rem;
  color: var(--text);
  background: #fafafa;
  transition: border-color 0.2s;
  outline: none;
}
input:focus, select:focus {
  border-color: var(--primary);
  background: #fff;
}

.row {
  display: flex;
  gap: 16px;
  margin: 14px 0;
}

#shortenForm {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
#shortenForm > .field { margin-bottom: 14px; }

button[type="submit"],
#submitBtn {
  width: 100%;
  padding: 12px;
  background: var(--primary);
  color: #fff;
  border: none;
  border-radius: 8px;
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  transition: background 0.2s;
  margin-top: 4px;
}
button[type="submit"]:hover { background: var(--primary-hover); }
button[type="submit"]:disabled { background: #aaa; cursor: not-allowed; }

/* ── Result ───────────────────────────────────────────────────────────── */
.result {
  margin-top: 20px;
  background: #f0fdf4;
  border: 1.5px solid #86efac;
  border-radius: 8px;
  padding: 16px 20px;
}
.result-label {
  font-size: 0.82rem;
  font-weight: 700;
  color: var(--success);
  margin-bottom: 10px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
.short-url-box {
  display: flex;
  align-items: center;
  gap: 10px;
}
.short-url-box a {
  flex: 1;
  font-size: 1rem;
  font-weight: 700;
  color: var(--primary);
  text-decoration: none;
  word-break: break-all;
}
.short-url-box a:hover { text-decoration: underline; }
#copyBtn {
  padding: 6px 14px;
  background: var(--primary);
  color: #fff;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-size: 0.85rem;
  white-space: nowrap;
  transition: background 0.2s;
}
#copyBtn:hover { background: var(--primary-hover); }
.result-meta {
  margin-top: 8px;
  font-size: 0.8rem;
  color: var(--muted);
}

/* ── Error ────────────────────────────────────────────────────────────── */
.error-msg {
  margin-top: 14px;
  padding: 10px 14px;
  background: #fef2f2;
  border: 1.5px solid #fca5a5;
  border-radius: 8px;
  color: var(--danger);
  font-size: 0.88rem;
}

/* ── Tabs ─────────────────────────────────────────────────────────────── */
.tabs {
  display: flex;
  gap: 8px;
  margin-bottom: 4px;
}
.tab {
  flex: 1;
  padding: 10px;
  background: var(--card);
  border: 1.5px solid var(--border);
  border-radius: 8px;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  color: var(--muted);
  transition: all 0.15s;
}
.tab.active {
  background: var(--primary);
  color: #fff;
  border-color: var(--primary);
}

/* ── URL List ─────────────────────────────────────────────────────────── */
.list-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}
.list-header h2 { margin-bottom: 0; }
#refreshBtn {
  padding: 6px 14px;
  background: transparent;
  border: 1.5px solid var(--border);
  border-radius: 6px;
  cursor: pointer;
  font-size: 0.85rem;
  color: var(--muted);
  transition: all 0.15s;
}
#refreshBtn:hover { border-color: var(--primary); color: var(--primary); }

.url-list { display: flex; flex-direction: column; gap: 12px; }

.url-item {
  border: 1.5px solid var(--border);
  border-radius: 10px;
  padding: 14px 16px;
  display: flex;
  align-items: flex-start;
  gap: 14px;
  transition: box-shadow 0.15s;
}
.url-item:hover { box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
.url-item.expired { opacity: 0.55; }

.url-item-info { flex: 1; min-width: 0; }
.url-item-short {
  font-weight: 700;
  color: var(--primary);
  font-size: 0.95rem;
  text-decoration: none;
}
.url-item-short:hover { text-decoration: underline; }
.url-item-original {
  font-size: 0.8rem;
  color: var(--muted);
  margin-top: 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.url-item-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 8px;
}
.badge {
  font-size: 0.72rem;
  padding: 2px 8px;
  border-radius: 20px;
  font-weight: 600;
}
.badge-click { background: #ede9fe; color: var(--primary); }
.badge-date { background: #f3f4f6; color: var(--muted); }
.badge-expires { background: #fef3c7; color: #92400e; }
.badge-custom { background: #dbeafe; color: #1d4ed8; }
.badge-expired { background: #fee2e2; color: var(--danger); }

.url-item-actions { display: flex; gap: 6px; align-items: flex-start; }
.btn-icon {
  padding: 5px 10px;
  border: 1.5px solid var(--border);
  border-radius: 6px;
  background: transparent;
  cursor: pointer;
  font-size: 0.78rem;
  color: var(--muted);
  transition: all 0.15s;
}
.btn-icon:hover { border-color: var(--danger); color: var(--danger); }

.empty-state {
  text-align: center;
  padding: 40px 0;
  color: var(--muted);
  font-size: 0.9rem;
}

/* ── Stats ────────────────────────────────────────────────────────────── */
.stats-search {
  display: flex;
  gap: 8px;
}
.stats-search input { flex: 1; }
#statsSearchBtn {
  padding: 10px 20px;
  background: var(--primary);
  color: #fff;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-weight: 600;
  transition: background 0.2s;
}
#statsSearchBtn:hover { background: var(--primary-hover); }

.stats-result {
  margin-top: 20px;
  border: 1.5px solid var(--border);
  border-radius: 10px;
  padding: 20px;
}
.stats-result h3 {
  font-size: 1rem;
  margin-bottom: 16px;
  color: var(--text);
}
.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 12px;
}
.stats-item {
  background: var(--bg);
  border-radius: 8px;
  padding: 14px;
}
.stats-item-label {
  font-size: 0.75rem;
  color: var(--muted);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.4px;
  margin-bottom: 6px;
}
.stats-item-value {
  font-size: 1.2rem;
  font-weight: 800;
  color: var(--text);
}
.stats-item-value.highlight { color: var(--primary); }
.stats-original {
  margin-top: 12px;
  font-size: 0.8rem;
  color: var(--muted);
  word-break: break-all;
}

/* ── Utility ──────────────────────────────────────────────────────────── */
.hidden { display: none !important; }

@media (max-width: 500px) {
  .row { flex-direction: column; }
  .card { padding: 20px 16px; }
}

